"use client";

import { Stepper as StepperRoot, type StepperProps } from "./stepper";
import { StepperStep, type StepperStepProps } from "./stepper-step";
import type { StepStatus, SubstepStatus } from "./stepper-context";
import {
  StepperTrigger,
  type StepperTriggerProps,
  DEFAULT_STEP_STATUS_LABELS,
  STEP_STATUS_BADGE_VARIANTS,
} from "./stepper-trigger";
import { StepperContent, type StepperContentProps } from "./stepper-content";
import {
  StepperSubstep,
  type StepperSubstepProps,
  type SubstepData,
  SUBSTEP_STATUS_BADGE_VARIANTS,
} from "./stepper-substep";

const Stepper = Object.assign(StepperRoot, {
  Step: StepperStep,
  Trigger: StepperTrigger,
  Content: StepperContent,
  Substep: StepperSubstep,
});

export { Stepper, type StepperProps };
export { StepperStep, type StepperStepProps, type StepStatus };
export { StepperTrigger, type StepperTriggerProps, DEFAULT_STEP_STATUS_LABELS, STEP_STATUS_BADGE_VARIANTS };
export { StepperContent, type StepperContentProps };
export { StepperSubstep, type StepperSubstepProps, type SubstepData, type SubstepStatus, SUBSTEP_STATUS_BADGE_VARIANTS };

"use client";

import { useMemo, type ComponentProps, type ReactNode } from "react";
import { cn } from "@/lib/utils";
import { StepperContext } from "./stepper-context";
import { useStepperState } from "./use-stepper-state";

export interface StepperProps
  extends Omit<ComponentProps<"ol">, "children"> {
  expandedIds?: string[];
  defaultExpandedIds?: string[];
  onExpandedChange?: (ids: string[]) => void;
  children: ReactNode;
}

export function Stepper({
  expandedIds,
  defaultExpandedIds,
  onExpandedChange,
  className,
  children,
  ...props
}: StepperProps) {
  const { expandedIds: expanded, toggle } = useStepperState({
    expandedIds,
    defaultExpandedIds,
    onExpandedChange,
  });

  const ctx = useMemo(() => ({ expandedIds: expanded, onToggle: toggle }), [expanded, toggle]);

  return (
    <StepperContext value={ctx}>
      <ol role="list" aria-label="Progress steps" {...props} className={cn("space-y-4 list-none m-0 p-0", className)}>
        {children}
      </ol>
    </StepperContext>
  );
}

"use client";

import { createContext, useContext } from "react";
import type { StepStatus } from "@/lib/step-status";

export type { StepStatus };
export type SubstepStatus = "pending" | "active" | "completed" | "error";

export interface StepperContextValue {
  expandedIds: string[];
  onToggle: (id: string) => void;
}

export const StepperContext = createContext<StepperContextValue | undefined>(undefined);

export function useStepperContext() {
  const context = useContext(StepperContext);
  if (!context) {
    throw new Error("Stepper parts must be used within a Stepper");
  }
  return context;
}

export interface StepperStepContextValue {
  stepId: string;
  isExpanded: boolean;
  status: StepStatus;
  triggerId: string;
  contentId: string;
  hasContent: boolean;
}

export const StepperStepContext = createContext<StepperStepContextValue | undefined>(undefined);

export function useStepperStepContext() {
  const context = useContext(StepperStepContext);
  if (!context) {
    throw new Error("StepperTrigger/StepperContent must be used within StepperStep");
  }
  return context;
}

"use client";

import { useCallback } from "react";
import { useControllableState } from "@/hooks/use-controllable-state";

export interface StepperStateProps {
  expandedIds?: string[];
  defaultExpandedIds?: string[];
  onExpandedChange?: (ids: string[]) => void;
}

export function useStepperState({
  expandedIds,
  defaultExpandedIds,
  onExpandedChange,
}: StepperStateProps) {
  const [expanded, setExpanded] = useControllableState<string[]>({
    value: expandedIds,
    defaultValue: defaultExpandedIds ?? [],
    onChange: onExpandedChange,
  });

  const toggle = useCallback((id: string) => {
    setExpanded((prev) =>
      prev.includes(id) ? prev.filter((v) => v !== id) : [...prev, id],
    );
  }, [setExpanded]);

  return { expandedIds: expanded, toggle };
}

"use client";

import { Children, isValidElement, type ComponentProps, type ReactNode, useId, useMemo } from "react";
import { useStepperContext, StepperStepContext, type StepStatus } from "./stepper-context";
import { StepperContent } from "./stepper-content";

export interface StepperStepProps
  extends Omit<ComponentProps<"li">, "children"> {
  stepId: string;
  status: StepStatus;
  children: ReactNode;
}

function hasStepperContent(children: ReactNode): boolean {
  return Children.toArray(children).some((child) => (
    isValidElement(child) && child.type === StepperContent
  ));
}

export function StepperStep({
  stepId,
  status,
  children,
  className,
  ...props
}: StepperStepProps) {
  const { expandedIds } = useStepperContext();
  const isExpanded = expandedIds.includes(stepId);

  const base = useId();
  const triggerId = `${base}-trigger`;
  const contentId = `${base}-content`;
  const hasContent = hasStepperContent(children);

  const ctx = useMemo(
    () => ({ stepId, isExpanded, status, triggerId, contentId, hasContent }),
    [stepId, isExpanded, status, triggerId, contentId, hasContent],
  );

  return (
    <StepperStepContext value={ctx}>
      <li {...props} className={className} data-state={isExpanded ? "open" : "closed"}>{children}</li>
    </StepperStepContext>
  );
}

"use client";

import type { ComponentProps, ReactNode } from "react";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { Badge } from "../badge/badge";
import { useStepperContext, useStepperStepContext, type StepStatus } from "./stepper-context";

const stepVariants = cva(
  "flex items-start gap-3 appearance-none bg-transparent border-0 p-0 text-left w-full font-[inherit] cursor-pointer disabled:cursor-not-allowed disabled:opacity-50",
  {
  variants: {
    status: {
      completed: "",
      active: "bg-secondary py-2 -mx-3 px-3 rounded border-l-2 border-foreground",
      pending: "",
      error: "bg-destructive/10 py-2 -mx-3 px-3 rounded border-l-2 border-destructive",
    },
  },
  defaultVariants: {
    status: "pending",
  },
});

const labelVariants = cva("text-sm", {
  variants: {
    status: {
      completed: "text-foreground",
      active: "font-bold text-foreground",
      pending: "text-muted-foreground",
      error: "font-medium text-destructive",
    },
  },
  defaultVariants: {
    status: "pending",
  },
});

export const STEP_STATUS_BADGE_VARIANTS: Record<StepStatus, "success" | "info" | "neutral" | "error"> = {
  completed: "success",
  active: "info",
  pending: "neutral",
  error: "error",
};

export const DEFAULT_STEP_STATUS_LABELS: Record<StepStatus, string> = {
  completed: "Completed",
  active: "Active",
  pending: "Pending",
  error: "Error",
};

export interface StepperTriggerProps
  extends Omit<ComponentProps<"button">, "children" | "type"> {
  children: ReactNode;
  /** Override the per-status badge text. Falls back to `DEFAULT_STEP_STATUS_LABELS`. */
  statusLabels?: Partial<Record<StepStatus, string>>;
}

export function StepperTrigger({ children, className, onClick, statusLabels, ...props }: StepperTriggerProps) {
  const { onToggle } = useStepperContext();
  const { stepId, isExpanded, status, triggerId, contentId, hasContent } = useStepperStepContext();
  const badgeLabel = statusLabels?.[status] ?? DEFAULT_STEP_STATUS_LABELS[status];

  return (
    <button
      type="button"
      {...props}
      className={cn(stepVariants({ status }), className)}
      onClick={(event) => {
        onClick?.(event);
        if (!event.defaultPrevented && hasContent) onToggle(stepId);
      }}
      aria-expanded={hasContent ? isExpanded : undefined}
      aria-controls={hasContent ? contentId : undefined}
      id={triggerId}
      aria-current={status === "active" ? "step" : undefined}
    >
      <span className="shrink-0">
        <Badge variant={STEP_STATUS_BADGE_VARIANTS[status]} size="sm" className="min-w-[48px] justify-center">
          {badgeLabel}
        </Badge>
      </span>
      <span className={labelVariants({ status })}>{children}</span>
    </button>
  );
}

"use client";

import type { ComponentProps, ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useStepperStepContext } from "./stepper-context";

export interface StepperContentProps
  extends Omit<ComponentProps<"div">, "children"> {
  children: ReactNode;
}

export function StepperContent({ children, className, ...props }: StepperContentProps) {
  const { isExpanded, triggerId, contentId } = useStepperStepContext();

  return (
    <div
      {...props}
      className={cn(
        "grid transition-[grid-template-rows] duration-200 ease-out",
        isExpanded ? "grid-rows-[1fr]" : "grid-rows-[0fr]",
        className,
      )}
      role="region"
      id={contentId}
      aria-labelledby={triggerId}
      aria-hidden={isExpanded ? undefined : true}
      inert={isExpanded ? undefined : true}
    >
      <div className="overflow-hidden min-h-0">
        <div className="pt-2 pl-7" hidden={!isExpanded}>
          {children}
        </div>
      </div>
    </div>
  );
}

"use client";

import type { ComponentProps } from "react";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { Badge } from "../badge/badge";
import type { SubstepStatus } from "./stepper-context";

export interface SubstepData {
  id: string;
  tag: string;
  label: string;
  status: SubstepStatus;
  detail?: string;
}

const substepVariants = cva("flex items-center gap-2 py-1 text-sm", {
  variants: {
    status: {
      pending: "text-muted-foreground",
      active: "text-foreground font-medium animate-pulse",
      completed: "text-foreground",
      error: "text-destructive font-medium",
    },
  },
  defaultVariants: { status: "pending" },
});

export const SUBSTEP_STATUS_BADGE_VARIANTS: Record<SubstepStatus, "success" | "info" | "error" | "neutral"> = {
  pending: "neutral",
  active: "info",
  completed: "success",
  error: "error",
};

const SUBSTEP_STATUS_LABEL_COLORS: Record<SubstepStatus, string | undefined> = {
  pending: undefined,
  active: "text-muted-foreground",
  completed: "text-success",
  error: "text-destructive",
};

export interface StepperSubstepProps
  extends Omit<ComponentProps<"div">, "children">,
    Omit<SubstepData, "id"> {
  /** Override per-status fallback text shown when `detail` is not provided. */
  statusLabels?: Partial<Record<SubstepStatus, string>>;
}

export function StepperSubstep({
  tag,
  label,
  status,
  detail,
  statusLabels,
  className,
  ...props
}: StepperSubstepProps) {
  const statusText = detail ?? statusLabels?.[status];
  const labelColor = SUBSTEP_STATUS_LABEL_COLORS[status];

  return (
    <div {...props} className={cn(substepVariants({ status }), className)}>
      <Badge variant={SUBSTEP_STATUS_BADGE_VARIANTS[status]} size="sm" className="min-w-[40px] justify-center">
        {tag}
      </Badge>
      <span>{label}</span>
      {statusText && (
        <span className={cn("ml-auto text-xs", detail ? "text-muted-foreground" : labelColor)}>
          {statusText}
        </span>
      )}
    </div>
  );
}
